import{b as r,J as t,g as o,j as e}from"./chunks/framework.DVAsBjJ_.js";const c=JSON.parse('{"title":"추진현황 (Roadmap)","description":"","frontmatter":{},"headers":[],"relativePath":"work-manage/roadmap.md","filePath":"work-manage/roadmap.md","lastUpdated":1780708460000}'),l={name:"work-manage/roadmap.md"};function i(n,a,s,h,d,u){return t(),o("div",null,[...a[0]||(a[0]=[e('<h1 id="추진현황-roadmap" tabindex="-1">추진현황 (Roadmap) <a class="header-anchor" href="#추진현황-roadmap" aria-label="Permalink to &quot;추진현황 (Roadmap)&quot;">​</a></h1><p><strong>추진현황</strong> 페이지는 프로젝트의 주요 마일스톤(단계/버전)별 진행 상황을 시각적으로 확인하고 관리하는 화면입니다. 프로젝트를 여러 단계로 나누어 각 목표 대비 현재 어느 정도 도달했는지 파악할 수 있습니다.</p><h2 id="_1-개요" tabindex="-1">1. 개요 <a class="header-anchor" href="#_1-개요" aria-label="Permalink to &quot;1. 개요&quot;">​</a></h2><p>프로젝트의 전체 일정을 큰 단위(단계)로 나누어 관리합니다. 각 단계에는 여러 개의 **업무(Issue)**가 연결되어 있으며, 이 업무들의 완료 상태가 모여 해당 단계의 전체 진행률을 결정합니다.</p><h2 id="_2-주요-기능-안내" tabindex="-1">2. 주요 기능 안내 <a class="header-anchor" href="#_2-주요-기능-안내" aria-label="Permalink to &quot;2. 주요 기능 안내&quot;">​</a></h2><h3 id="📊-단계별-진행도-확인" tabindex="-1">📊 단계별 진행도 확인 <a class="header-anchor" href="#📊-단계별-진행도-확인" aria-label="Permalink to &quot;📊 단계별 진행도 확인&quot;">​</a></h3><ul><li><strong>진행바(Progress Bar)</strong>: 각 단계 카드에는 전체 업무 중 완료된 업무의 비율이 그래프로 표시되어 직관적인 확인이 가능합니다.</li><li><strong>상태 요약</strong>: 단계별로 &#39;전체 업무 수&#39;, &#39;완료된 업무&#39;, &#39;진행 중인 업무&#39; 건수를 숫자로 보여주어 상세 수치를 파악할 수 있습니다.</li></ul><h3 id="🔍-단계-상세-조회-및-업무-확인" tabindex="-1">🔍 단계 상세 조회 및 업무 확인 <a class="header-anchor" href="#🔍-단계-상세-조회-및-업무-확인" aria-label="Permalink to &quot;🔍 단계 상세 조회 및 업무 확인&quot;">​</a></h3><ul><li>특정 단계의 제목을 클릭하면 해당 단계의 상세 정보 화면으로 이동합니다.</li><li><strong>연결된 업무</strong>: 해당 단계에 할당된 모든 업무 목록을 확인할 수 있습니다. 완료된 업무는 취소선으로 표시되어 구분하기 쉽습니다.</li><li><strong>설명</strong>: 단계 생성 시 입력한 목표나 세부 설명을 확인할 수 있습니다.</li></ul><h3 id="➕-단계-관리-추가-수정-삭제" tabindex="-1">➕ 단계 관리 (추가/수정/삭제) <a class="header-anchor" href="#➕-단계-관리-추가-수정-삭제" aria-label="Permalink to &quot;➕ 단계 관리 (추가/수정/삭제)&quot;">​</a></h3><ul><li><strong>새 단계 추가</strong>: 우측 상단의 <strong>[새 단계]</strong> 링크를 클릭하여 프로젝트의 새로운 마일스톤을 정의합니다.</li><li><strong>편집 및 삭제</strong>: 단계 상세 화면 상단에서 기존 단계의 정보를 수정하거나, 필요 없는 단계를 삭제할 수 있습니다.</li></ul><h3 id="⚙️-설정-연동" tabindex="-1">⚙️ 설정 연동 <a class="header-anchor" href="#⚙️-설정-연동" aria-label="Permalink to &quot;⚙️ 설정 연동&quot;">​</a></h3><ul><li>화면 우측 상단의 더보기(점 세 개 아이콘) 메뉴를 통해 프로젝트 설정의 <strong>[단계]</strong> 탭으로 즉시 이동하여 모든 마일스톤을 한꺼번에 관리할 수 있습니다.</li></ul><h2 id="_3-화면-구성-상세" tabindex="-1">3. 화면 구성 상세 <a class="header-anchor" href="#_3-화면-구성-상세" aria-label="Permalink to &quot;3. 화면 구성 상세&quot;">​</a></h2><h3 id="진행률-계산-방식" tabindex="-1">진행률 계산 방식 <a class="header-anchor" href="#진행률-계산-방식" aria-label="Permalink to &quot;진행률 계산 방식&quot;">​</a></h3><ul><li>해당 단계에 연결된 모든 업무의 **완료 비율(Done Ratio)**을 합산하여 평균을 낸 수치입니다. 모든 업무가 100% 완료되면 단계의 진행률도 100%가 됩니다.</li></ul><h3 id="단계-상태-status" tabindex="-1">단계 상태(Status) <a class="header-anchor" href="#단계-상태-status" aria-label="Permalink to &quot;단계 상태(Status)&quot;">​</a></h3><ul><li><strong>진행 중 (Open)</strong>: 현재 활발히 업무가 진행되고 있는 단계입니다.</li><li><strong>잠김 (Locked)</strong>: 업무 추가는 제한되나 진행 상황은 계속 추적하는 단계입니다.</li><li><strong>닫힘 (Closed)</strong>: 모든 목표가 달성되어 종료된 단계입니다.</li></ul><h2 id="_4-이용-팁" tabindex="-1">4. 이용 팁 <a class="header-anchor" href="#_4-이용-팁" aria-label="Permalink to &quot;4. 이용 팁&quot;">​</a></h2><ul><li><strong>업무 할당</strong>: 새로운 업무를 만들거나 수정할 때 &#39;목표 버전&#39; 또는 &#39;단계&#39; 필드에서 특정 마일스톤을 선택하면 추진현황에 자동으로 반영됩니다.</li><li><strong>빠른 업무 관리</strong>: 상세 화면의 업무 목록 우측 드롭다운을 이용하면 페이지 이동 없이 업무 상태를 즉시 변경할 수 있어 편리합니다.</li></ul><h2 id="_5-추진현황-메뉴가-보이지-않나요-노출-조건" tabindex="-1">5. 추진현황 메뉴가 보이지 않나요? (노출 조건) <a class="header-anchor" href="#_5-추진현황-메뉴가-보이지-않나요-노출-조건" aria-label="Permalink to &quot;5. 추진현황 메뉴가 보이지 않나요? (노출 조건)&quot;">​</a></h2><p>프로젝트 메뉴에서 &#39;추진현황&#39; 탭이 보이지 않는다면 다음 사항을 확인해 보세요.</p><ul><li><strong>등록된 단계(버전) 없음</strong>: 프로젝트에 등록된 &#39;단계&#39;가 하나도 없을 경우 추진현황 메뉴는 자동으로 숨겨집니다. <strong>[설정 &gt; 단계]</strong> 메뉴에서 새로운 단계를 하나 이상 생성하면 메뉴가 나타납니다.</li></ul>',23)])])}const m=r(l,[["render",i]]);export{c as __pageData,m as default};
